-- Get Jhemilly's ID
SET @jhemilly_id = (SELECT id FROM users WHERE email = 'jhemilly.viana@grupoesol.com.br' LIMIT 1);

-- Get cycle IDs for Jan and Feb
SET @jan_id = (SELECT id FROM cycles WHERE monthYear = '2026-01' LIMIT 1);
SET @feb_id = (SELECT id FROM cycles WHERE monthYear = '2026-02' LIMIT 1);

-- Insert Jan aggregate
INSERT INTO aggregates (cycleId, userId, nota360, notaLideranca, avaliacaoGlobal, bonusPontualidade, bonusDesempenho, bonusPodio, totalBonus, radarData)
VALUES (@jan_id, @jhemilly_id, 10.00, 10.00, 10.00, 125.00, 125.00, 0.00, 250.00, '{"Comunicação & Postura":10,"Qualidade & Técnica":10,"Processos & Prazos":10,"Autonomia & Proatividade":10,"Segurança & Zelo":10}')
ON DUPLICATE KEY UPDATE nota360 = VALUES(nota360);

-- Insert Feb aggregate
INSERT INTO aggregates (cycleId, userId, nota360, notaLideranca, avaliacaoGlobal, bonusPontualidade, bonusDesempenho, bonusPodio, totalBonus, radarData)
VALUES (@feb_id, @jhemilly_id, 10.00, 10.00, 10.00, 125.00, 125.00, 0.00, 250.00, '{"Comunicação & Postura":10,"Qualidade & Técnica":10,"Processos & Prazos":10,"Autonomia & Proatividade":10,"Segurança & Zelo":10}')
ON DUPLICATE KEY UPDATE nota360 = VALUES(nota360);

-- Insert punctuality for Jan/Feb
INSERT INTO punctuality (cycleId, userId, maxDelayDayMin, totalDelayMonthMin, eligible) VALUES (@jan_id, @jhemilly_id, 0, 0, 1) ON DUPLICATE KEY UPDATE eligible = 1;
INSERT INTO punctuality (cycleId, userId, maxDelayDayMin, totalDelayMonthMin, eligible) VALUES (@feb_id, @jhemilly_id, 0, 0, 1) ON DUPLICATE KEY UPDATE eligible = 1;

